-/// Simple URL encoding for project names.
+/// URL percent-encoding for query parameters.
+///
+/// Encodes characters that are not URL-safe (RFC 3986 unreserved characters).
 fn urlencoding_encode(s: &str) -> String {
-    s.replace(' ', "%20")
